* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
header { background: #333; color: #fff; padding: 1rem; text-align: center; }
nav a { color: #fff; margin: 0 1rem; text-decoration: none; }
main { max-width: 1200px; margin: 0 auto; padding: 2rem; }
section { margin-bottom: 3rem; }
.project-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(300px, 1fr)); gap: 2rem; }
.project { background: #f4f4f4; padding: 2rem; text-align: center; border-radius: 5px; }
form { display: flex; flex-direction: column; gap: 1rem; max-width: 500px; }
input, textarea { padding: 0.5rem; border: 1px solid #ddd; border-radius: 3px; }
button { background: #333; color: #fff; padding: 0.5rem 1rem; border: none; cursor: pointer; }
@media (max-width: 768px) { .project-grid { grid-template-columns: 1fr; } }

document.getElementById('contact-form')?.addEventListener('submit', function(e) {
    e.preventDefault();
    alert('Message sent! (This is a demo)');
    this.reset();
});
